export async function getCollection(
  handle: string
): Promise<Collection | undefined> {
  "use cache";
  cacheTag(TAGS.collections);
  cacheLife("days");

  const res = await shopifyFetch<ShopifyCollectionOperation>({
    query: getCollectionQuery,
    variables: {
      handle,
    },
  });

  return reshapeCollection(res.body.data.collection);
}

export async function getProductRecommendations(
  productId: string
): Promise<Product[]> {
  "use cache";
  cacheTag(TAGS.products);
  cacheLife("days");

  const res = await shopifyFetch<ShopifyProductRecommendationsOperation>({
    query: getProductRecommendationsQuery,
    variables: {
      productId,
    },
  });

  return reshapeProducts(res.body.data.productRecommendations);
}

export default function validateLocale(locale: string) {
  try {
    const constructed = new Intl.Locale(locale);
    if (!constructed.language) {
      throw new Error('Language is required');
    }
  } catch {
    console.error(
      `An invalid locale was provided: "${locale}"\nPlease ensure you're using a valid Unicode locale identifier (e.g. "en-US").`
    );
  }
}

constructor(
  option: CookieOption,
  cookies: RequestInternal["cookies"],
  logger: LoggerInstance | Console
) {
  this.#logger = logger
  this.#option = option
  if (!cookies) return

  const { name: sessionCookiePrefix } = option

  for (const [name, value] of Object.entries(cookies)) {
    if (!name.startsWith(sessionCookiePrefix) || !value) continue
    this.#chunks[name] = value
  }
}

export function assertInternalOptionsWebAuthn(
  options: InternalOptions
): InternalOptionsWebAuthn {
  const { provider, adapter } = options

  // Adapter is required for WebAuthn
  if (!adapter)
    throw new MissingAdapter("An adapter is required for the WebAuthn provider")
  // Provider must be WebAuthn
  if (!provider || provider.type !== "webauthn") {
    throw new InvalidProvider("Provider must be WebAuthn")
  }
  // Narrow the options type for typed usage later
  return { ...options, provider, adapter }
}

async create(options: InternalOptions<"oauth">) {
  const code_verifier = o.generateRandomCodeVerifier()
  const value = await o.calculatePKCECodeChallenge(code_verifier)
  const cookie = await sealCookie("pkceCodeVerifier", code_verifier, options)
  return { cookie, value }
}

function calculateRelativeTimeValue(
  seconds: number,
  unit: Intl.RelativeTimeFormatUnit
) {
  // We have to round the resulting values, as `Intl.RelativeTimeFormat`
  // will include fractions like '2.1 hours ago'.
  return Math.round(seconds / UNIT_SECONDS[unit]);
}

private getCatalogLocales(): CatalogLocales {
  if (this.catalogLocales) {
    return this.catalogLocales;
  } else {
    const messagesDir = path.join(this.projectRoot, this.config.extract.path);
    this.catalogLocales = new CatalogLocales({
      messagesDir,
      extension: getFormatExtension(this.config.messages.format),
      locales: this.config.extract.locales,
      sourceLocale: this.config.extract.sourceLocale
    });
    return this.catalogLocales;
  }
}

private async loadSourceMessages(): Promise<Map<string, ExtractorMessage>> {
  // Load source catalog to hydrate metadata (e.g. flags) later without
  // treating catalog entries as source of truth.
  const diskMessages = await this.loadLocaleMessages(
    this.config.extract.sourceLocale
  );
  const byId = new Map<string, ExtractorMessage>();
  for (const diskMessage of diskMessages) {
    byId.set(diskMessage.id, diskMessage);
  }
  return byId;
}

public static shouldEnterDirectory(
  dirPath: string,
  srcPaths: Array<string>
): boolean {
  const dirName = path.basename(dirPath);
  if (SourceFileFilter.IGNORED_DIRECTORIES.includes(dirName)) {
    return SourceFileFilter.isIgnoredDirectoryExplicitlyIncluded(
      dirPath,
      srcPaths
    );
  }
  return true;
}

export function DrizzleAdapter<SqlFlavor extends SqlFlavorOptions>(
  db: SqlFlavor,
  schema?: DefaultSchema<SqlFlavor>
): Adapter {
  if (is(db, MySqlDatabase)) {
    return MySqlDrizzleAdapter(db, schema as DefaultMySqlSchema)
  } else if (is(db, PgDatabase)) {
    return PostgresDrizzleAdapter(db, schema as DefaultPostgresSchema)
  } else if (is(db, BaseSQLiteDatabase)) {
    return SQLiteDrizzleAdapter(db, schema as DefaultSQLiteSchema)
  }

  throw new Error(
    `Unsupported database type (${typeof db}) in Auth.js Drizzle adapter.`
  )
}

private async loadLocaleMessages(
  locale: Locale
): Promise<Array<ExtractorMessage>> {
  const persister = await this.getPersister();
  const messages = await persister.read(locale);
  const fileTime = await persister.getLastModified(locale);
  this.lastWriteByLocale.set(locale, fileTime);
  return messages;
}

export function formatPathname(
  pathname: string,
  prefix: string | undefined,
  search: string | undefined
) {
  let result = pathname;

  if (prefix) {
    result = prefixPathname(prefix, result);
  }

  if (search) {
    result += search;
  }
  return result;
}

export async function getRegistriesIndex(options?: { useCache?: boolean }) {
  // Fetch new format and transform to old Record<string, string> for backward compatibility.
  const registries = await getRegistries(options)
  if (!registries) return null
  return Object.fromEntries(registries.map((r) => [r.name, r.url])) as z.infer<
    typeof registriesIndexSchema
  >
}

constructor(public readonly cwd: string) {
  const message = `No components.json found in ${cwd} or parent directories.`

  super(message, {
    code: RegistryErrorCode.NOT_CONFIGURED,
    context: { cwd },
    suggestion:
      "Run 'npx shadcn@latest init' to create a components.json file, or check that you're in the correct directory.",
  })
  this.name = "ConfigMissingError"
}

export function getMessagesFromConfig(
  config: Awaited<ReturnType<typeof getConfig>>
): ReturnType<typeof useMessagesType> {
  if (!config.messages) {
    throw new Error(
      'No messages found. Have you configured them correctly? See https://next-intl.dev/docs/configuration#messages'
    );
  }
  return config.messages;
}

export function getLocalizedTemplate<AppLocales extends Locales>(
  pathnameConfig: Pathnames<AppLocales>[keyof Pathnames<AppLocales>],
  locale: AppLocales[number],
  internalTemplate: string
) {
  return typeof pathnameConfig === 'string'
    ? pathnameConfig
    : pathnameConfig[locale] || internalTemplate;
}

private async processFile(absoluteFilePath: string): Promise<boolean> {
  const messages = await this.extractFile(absoluteFilePath);

  // `undefined` only when `extractFile()` throws. An empty array is success
  // and must still run `applyFileMessages` to clear stale ids for this file.
  if (!messages) return false;

  return this.applyFileMessages(absoluteFilePath, messages);
}
